SELECT AVG(probability) AS average_probability
FROM probabilities
WHERE disease_id = 1;

SELECT age_group_id, COUNT(DISTINCT health_state_from_id) AS distinct_health_states
FROM probabilities
GROUP BY age_group_id;

SELECT health_state_name, description
FROM health_states
ORDER BY health_state_name ASC;

SELECT probability
FROM probabilities
WHERE disease_id = 1 AND age_group_id = 2;

SELECT disease_name, COUNT(*) AS number_of_appearances
FROM diseases
WHERE disease_id = 1;

SELECT health_state_name, COUNT(*) AS health_state_count
FROM health_states
GROUP BY health_state_name;
